// MARK: - Ethereum RPC

final class EthereumRPCClient {
    var endpointURL: URL = URL(string: "https://cloudflare-eth.com")!
    private let session: URLSession = .shared

    func getBalance(address: String, tag: String) async throws -> String {
        try await call(method: "eth_getBalance", params: [address, tag])
    }

    func getTransactionCount(address: String, tag: String) async throws -> String {
        try await call(method: "eth_getTransactionCount", params: [address, tag])
    }

    func sendRawTransaction(rawTx: String) async throws -> String {
        try await call(method: "eth_sendRawTransaction", params: [rawTx])
    }

    private func call(method: String, params: [Any]) async throws -> String {
        let id = Int.random(in: 1...Int.max)
        let body: [String: Any] = [
            "jsonrpc": "2.0",
            "id": id,
            "method": method,
            "params": params
        ]
        var req = URLRequest(url: endpointURL)
        req.httpMethod = "POST"
        req.setValue("application/json", forHTTPHeaderField: "Content-Type")
        req.httpBody = try JSONSerialization.data(withJSONObject: body, options: [])

        let (data, resp) = try await session.data(for: req)
        guard (resp as? HTTPURLResponse)?.statusCode == 200 else {
            throw WalletError.invalidRPCResponse
        }
        let obj = try JSONSerialization.jsonObject(with: data, options: [])
        guard let dict = obj as? [String: Any] else { throw WalletError.invalidRPCResponse }
        if let err = dict["error"] as? [String: Any] {
            let msg = (err["message"] as? String) ?? "Unknown"
            throw WalletError.rpcError(msg)
        }
        guard let result = dict["result"] as? String else { throw WalletError.invalidRPCResponse }
        return result
    }
}

// MARK: - Signing (secp256k1 via CryptoKit P256 placeholder if needed? Implement proper secp256k1)

final class EthereumSigner {
    func generatePrivateKey() -> Data {
        var bytes = [UInt8](repeating: 0, count: 32)
        repeat {
            _ = SecRandomCopyBytes(kSecRandomDefault, bytes.count, &bytes)
        } while bytes.allSatisfy({ $0 == 0 })
        return Data(bytes)
    }

    func address(fromPrivateKey privateKey: Data) -> String {
        let pub = secp256k1PublicKeyUncompressed(fromPrivateKey: privateKey)
        let hash = Keccak256.hash(pub.dropFirst(1)) // drop 0x04
        let addr = hash.suffix(20)
        return "0x" + addr.hexString()
    }

    func sign(transaction: EthereumTransaction, privateKey: Data) throws -> String {
        let chainId = transaction.chainId

        let rlpUnsigned = RLP.encode([
            transaction.nonce.rlpItem(),
            transaction.gasPrice.rlpItem(),
            transaction.gasLimit.rlpItem(),
            transaction.to.rlpItem(),
            transaction.value.rlpItem(),
            transaction.data.rlpItem(),
            chainId.rlpItem(),
            Data().rlpItem(),
            Data().rlpItem()
        ])

        guard let unsigned = rlpUnsigned else { throw WalletError.rlpEncoding }

        let txHash = Keccak256.hash(unsigned)

        let sig = try secp256k1Sign(hash32: txHash, privateKey: privateKey)
        let recId = sig.recid

        let v = chainId * 2 + 35 + BigUInt(UInt64(recId))
        let r = BigUInt(data: sig.r)
        let s = BigUInt(data: sig.s)

        let rlpSigned = RLP.encode([
            transaction.nonce.rlpItem(),
            transaction.gasPrice.rlpItem(),
            transaction.gasLimit.rlpItem(),
            transaction.to.rlpItem(),
            transaction.value.rlpItem(),
            transaction.data.rlpItem(),
            v.rlpItem(),
            r.rlpItem(),
            s.rlpItem()
        ])

        guard let signed = rlpSigned else { throw WalletError.rlpEncoding }
        return "0x" + signed.hexString()
    }
}

// MARK: - secp256k1 minimal implementation (Swift port using Security?)
// NOTE: For MVP, this is a lightweight pure-Swift secp256k1 implementation subset for key->pub and signing.
// It is NOT constant-time; do not use for production without audited library.

struct Secp256k1Signature {
    let r: Data
    let s: Data
    let recid: Int
}

private func secp256k1PublicKeyUncompressed(fromPrivateKey privateKey: Data) -> Data {
    let pk = Secp256k1.PrivateKey(raw: privateKey)!
    return pk.publicKeyUncompressed
}

private func secp256k1Sign(hash32: Data, privateKey: Data) throws -> Secp256k1Signature {
    guard hash32.count == 32 else { throw WalletError.signingFailed }
    guard let pk = Secp256k1.PrivateKey(raw: privateKey) else { throw WalletError.signingFailed }
    let sig = pk.signRecoverable(message32: hash32)
    return Secp256k1Signature(r: sig.r, s: sig.s, recid: sig.recid)
}

enum Secp256k1 {
    struct PrivateKey {
        let d: BigUInt
        init?(raw: Data) {
            guard raw.count == 32 else { return nil }
            let x = BigUInt(data: raw)
            if x == 0 || x >= Curve.n { return nil }
            d = x
        }

        var publicKeyUncompressed: Data {
            let Q = Curve.mulG(d)
            var out = Data([0x04])
            out.append(Q.x.toFixed32())
            out.append(Q.y.toFixed32())
            return out
        }

        func signRecoverable(message32: Data) -> (r: Data, s: Data, recid: Int) {
            let z = BigUInt(data: message32)
            while true {
                let k = Curve.randomScalar()
                let R = Curve.mulG(k)
                let r = R.x % Curve.n
                if r == 0 { continue }
                let kinv = Curve.invMod(k, Curve.n)
                var s = (kinv * (z + r * d)) % Curve.n
                if s == 0 { continue }
                var recid = 0
                if R.y.isOdd { recid |= 1 }
                if R.x >= Curve.n { recid |= 2 }

                let halfN = Curve.n >> 1
                if s > halfN {
                    s = Curve.n - s
                    recid ^= 1
                }

                return (r.toFixed32(), s.toFixed32(), recid)
            }
        }
    }

    enum Curve {
        static let p = BigUInt(hex: "FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFEFFFFFC2F")!
        static let n = BigUInt(hex: "FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFEBAAEDCE6AF48A03BBFD25E8CD0364141")!
        static let Gx = BigUInt(hex: "79BE667EF9DCBBAC55A06295CE870B07029BFCDB2DCE28D959F2815B16F81798")!
        static let Gy = BigUInt(hex: "483ADA7726A3C4655DA4FBFC0E1108A8FD17B448A68554199C47D08FFB10D4B8")!

        struct Point {
            let x: BigUInt
            let y: BigUInt
            let inf: Bool
            static let infinity = Point(x: 0, y: 0, inf: true)
        }

        static func randomScalar() -> BigUInt {
            var b = [UInt8](repeating: 0, count: 32)
            var x: BigUInt = 0
            repeat {
                _ = SecRandomCopyBytes(kSecRandomDefault, b.count, &b)
                x = BigUInt(data: Data(b)) % n
            } while x == 0
            return x
        }

        static func invMod(_ a: BigUInt, _ m: BigUInt) -> BigUInt {
            a.power(m - 2, mod: m)
        }

        static func add(_ P: Point, _ Q: Point) -> Point {
            if P.inf { return Q }
            if Q.inf { return P }
            if P.x == Q.x {
                if (P.y + Q.y) % p == 0 { return .infinity }
                return dbl(P)
            }
            let lambda = ((Q.y + p - P.y) * invMod((Q.x + p - P.x) % p, p)) % p
            let xr = (lambda.power(2, mod: p) + p - P.x + p - Q.x) % p
            let yr = (lambda * ((P.x + p - xr) % p) + p - P.y) % p
            return Point(x: xr, y: yr, inf: false)
        }

        static func dbl(_ P: Point) -> Point {
            if P.inf { return P }
            if P.y == 0 { return .infinity }
            let lambda = ((BigUInt(3) * P.x.power(2, mod: p)) * invMod((BigUInt(2) * P.y) % p, p)) % p
            let xr = (lambda.power(2, mod: p) + p - (BigUInt(2) * P.x) % p) % p
            let yr = (lambda * ((P.x + p - xr) % p) + p - P.y) % p
            return Point(x: xr, y: yr, inf: false)
        }

        static func mulG(_ k: BigUInt) -> Point {
            mul(Point(x: Gx, y: Gy, inf: false), k)
        }

        static func mul(_ P: Point, _ k: BigUInt) -> Point {
            var N = P
            var Q = Point.infinity
            var scalar = k
            while scalar > 0 {
                if scalar.isOdd { Q = add(Q, N) }
                N = dbl(N)
                scalar >>= 1
            }
            return Q
        }
    }
}

