// MARK: - SHA3 (Keccak) minimal

struct SHA3 {
    enum Variant { case keccak256 }
    private var state = [UInt64](repeating: 0, count: 25)
    private var buffer = Data()
    private let rate: Int = 136
    private let outputLen: Int = 32

    init(variant: Variant) {}

    mutating func update(data: Data) {
        buffer.append(data)
        while buffer.count >= rate {
            let block = buffer.prefix(rate)
            absorb(block)
            buffer.removeFirst(rate)
            keccakF()
        }
    }

    mutating func finalize() -> Data {
        var padded = buffer
        padded.append(0x01)
        while (padded.count % rate) != rate - 1 { padded.append(0x00) }
        padded.append(0x80)
        while padded.count >= rate {
            absorb(padded.prefix(rate))
            padded.removeFirst(rate)
            keccakF()
        }
        var out = Data()
        while out.count < outputLen {
            out.append(squeeze(rate))
            if out.count >= outputLen { break }
            keccakF()
        }
        return out.prefix(outputLen)
    }

    private mutating func absorb(_ block: Data) {
        for i in 0..<(rate / 8) {
            let w = block.withUnsafeBytes { ptr -> UInt64 in
                let base = ptr.baseAddress!.assumingMemoryBound(to: UInt8.self)
                var v: UInt64 = 0
                for b in 0..<8 { v |= UInt64(base[i*8+b]) << (8*b) }
                return v
            }
            state[i] ^= w
        }
    }

    private func squeeze(_ n: Int) -> Data {
        var out = Data(count: n)
        out.withUnsafeMutableBytes { ptr in
            let base = ptr.baseAddress!.assumingMemoryBound(to: UInt8.self)
            for i in 0..<(n/8) {
                let v = state[i]
                for b in 0..<8 { base[i*8+b] = UInt8((v >> (8*b)) & 0xFF) }
            }
        }
        return out
    }

    private mutating func keccakF() {
        let rnd: [UInt64] = [
            0x0000000000000001,0x0000000000008082,0x800000000000808A,0x8000000080008000,
            0x000000000000808B,0x0000000080000001,0x8000000080008081,0x8000000000008009,
            0x000000000000008A,0x0000000000000088,0x0000000080008009,0x000000008000000A,
            0x000000008000808B,0x800000000000008B,0x8000000000008089,0x8000000000008003,
            0x8000000000008002,0x8000000000000080,0x000000000000800A,0x800000008000000A,
            0x8000000080008081,0x8000000000008080,0x0000000080000001,0x8000000080008008
        ]
        let r: [[Int]] = [
            [ 0,36, 3,41,18],
            [ 1,44,10,45, 2],
            [62, 6,43,15,61],
            [28,55,25,21,56],
            [27,20,39, 8,14]
        ]

        for rc in rnd {
            var C = [UInt64](repeating: 0, count: 5)
            for x in 0..<5 {
                C[x] = state[x] ^ state[x+5] ^ state[x+10] ^ state[x+15] ^ state[x+20]
            }
            var D = [UInt64](repeating: 0, count: 5)
            for x in 0..<5 {
                D[x] = C[(x+4)%5] ^ rotl(C[(x+1)%5], 1)
            }
            for x in 0..<5 {
                for y in 0..<5 {
                    state[x + 5*y] ^= D[x]
                }
            }

            var B = [UInt64](repeating: 0, count: 25)
            for x in 0..<5 {
                for y in 0..<5 {
                    let idx = x + 5*y
                    let nx = y
                    let ny = (2*x + 3*y) % 5
                    B[nx + 5*ny] = rotl(state[idx], r[x][y])
                }
            }

            for x in 0..<5 {
                for y in 0..<5 {
                    state[x + 5*y] = B[x + 5*y] ^ ((~B[(x+1)%5 + 5*y]) & B[(x+2)%5 + 5*y])
                }
            }

            state[0] ^= rc
        }
    }

    private func rotl(_ x: UInt64, _ n: Int) -> UInt64 {
        (x << UInt64(n)) | (x >> UInt64(64 - n))
    }
}

// MARK: - RLP

enum RLP {
    static func encode(_ items: [RLPItem]) -> Data? {
        var payload = Data()
        for i in items {
            payload.append(i.encode())
        }
        return encodeLength(payload.count, offset: 0xC0) + payload
    }

    static func encode(_ item: RLPItem) -> Data {
        item.encode()
    }

    private static func encodeLength(_ length: Int, offset: UInt8) -> Data {
        if length < 56 {
            return Data([offset + UInt8(length)])
        } else {
            let lenData = BigUInt(UInt64(length)).toMinimalBytes()
            return Data([offset + 55 + UInt8(lenData.count)]) + lenData
        }
    }
}

enum RLPItem {
    case bytes(Data)
    case list([RLPItem])

    func encode() -> Data {
        switch self {
        case .bytes(let b):
            if b.count == 1, let first = b.first, first < 0x80 {
                return b
            }
            if b.count < 56 {
                return Data([0x80 + UInt8(b.count)]) + b
            } else {
                let len = BigUInt(UInt64(b.count)).toMinimalBytes()
                return Data([0xB7 + UInt8(len.count)]) + len + b
            }
        case .list(let l):
            var payload = Data()
            for x in l { payload.append(x.encode()) }
            if payload.count < 56 {
                return Data([0xC0 + UInt8(payload.count)]) + payload
            } else {
                let len = BigUInt(UInt64(payload.count)).toMinimalBytes()
                return Data([0xF7 + UInt8(len.count)]) + len + payload
            }
        }
    }
}

// MARK: - BigUInt (minimal)

struct BigUInt: Comparable, ExpressibleByIntegerLiteral {
    private var words: [UInt32] // little-endian base 2^32

    init(integerLiteral value: UInt64) { self.init(value) }
    init(_ v: UInt64) {
        if v == 0 { words = [] }
        else {
            let lo = UInt32(truncatingIfNeeded: v)
            let hi = UInt32(truncatingIfNeeded: v >> 32)
            words = hi == 0 ? [lo] : [lo, hi]
        }
    }

    init?(hex: String) {
        let s = hex.strip0x()
        guard !s.isEmpty else { self.init(0); return }
        var x = BigUInt(0)
        for ch in s {
            let v: UInt8
            switch ch {
            case "0"..."9": v = UInt8(ch.unicodeScalars.first!.value - Unicode.Scalar("0").value)
            case "a"..."f": v = UInt8(ch.unicodeScalars.first!.value - Unicode.Scalar("a").value + 10)
            case "A"..."F": v = UInt8(ch.unicodeScalars.first!.value - Unicode.Scalar("A").value + 10)
            default: return nil
            }
            x = (x << 4) + BigUInt(UInt64(v))
        }
        self = x
    }

    init(data: Data) {
        var x = BigUInt(0)
        for b in data {
            x = (x << 8) + BigUInt(UInt64(b))
        }
        self = x
    }

    static func < (lhs: BigUInt, rhs: BigUInt) -> Bool {
        if lhs.words.count != rhs.words.count { return lhs.words.count < rhs.words.count }
        for i in stride(from: lhs.words.count - 1, through: 0, by: -1) {
            if lhs.words[i] != rhs.words[i] { return lhs.words[i] < rhs.words[i] }
        }
        return false
    }

    static func == (lhs: BigUInt, rhs: BigUInt) -> Bool { lhs.words == rhs.words }

    var isOdd: Bool { (words.first ?? 0) & 1 == 1 }

    static func + (a: BigUInt, b: BigUInt) -> BigUInt {
        let n = max(a.words.count, b.words.count)
        var out = [UInt32](repeating: 0, count: n)
        var carry: UInt64 = 0
        for i in 0..<n {
            let av = i < a.words.count ? UInt64(a.words[i]) : 0
            let bv = i < b.words.count ? UInt64(b.words[i]) : 0
            let sum = av + bv + carry
            out[i] = UInt32(truncatingIfNeeded: sum)
            carry = sum >> 32
        }
        if carry != 0 { out.append(UInt32(carry)) }
        return BigUInt(words: out).normalized()
    }

    static func - (a: BigUInt, b: BigUInt) -> BigUInt {
        precondition(a >= b)
        var out = a.words
        var borrow: Int64 = 0
        for i in 0..<out.count {
            let av = Int64(UInt64(out[i]))
            let bv = Int64(i < b.words.count ? UInt64(b.words[i]) : 0)
            var v = av - bv + borrow
            if v < 0 {
                v += Int64(1) << 32
                borrow = -1
            } else {
                borrow = 0
            }
            out[i] = UInt32(truncatingIfNeeded: v)
        }
        return BigUInt(words: out).normalized()
    }

    static func * (a: BigUInt, b: BigUInt) -> BigUInt {
        if a.words.isEmpty || b.words.isEmpty { return BigUInt(0) }
        var out = [UInt32](repeating: 0, count: a.words.count + b.words.count)
        for i in 0..<a.words.count {
            var carry: UInt64 = 0
            for j in 0..<b.words.count {
                let idx = i + j
                let prod = UInt64(a.words[i]) * UInt64(b.words[j]) + UInt64(out[idx]) + carry
                out[idx] = UInt32(truncatingIfNeeded: prod)
                carry = prod >> 32
            }
            var k = i + b.words.count
            while carry != 0 {
                let sum = UInt64(out[k]) + carry
                out[k] = UInt32(truncatingIfNeeded: sum)
                carry = sum >> 32
                k += 1
            }
        }
        return BigUInt(words: out).normalized()
    }

    static func >> (a: BigUInt, shift: Int) -> BigUInt {
        if shift == 0 { return a }
        let wordShift = shift / 32
        let bitShift = shift % 32
        if wordShift >= a.words.count { return BigUInt(0) }
        var out = [UInt32](repeating: 0, count: a.words.count - wordShift)
        var carry: UInt32 = 0
        for i in stride(from: a.words.count - 1, through: wordShift, by: -1) {
            let w = a.words[i]
            let idx = i - wordShift
            if bitShift == 0 {
                out[idx] = w
            } else {
                out[idx] = (w >> UInt32(bitShift)) | (carry << UInt32(32 - bitShift))
                carry = w & ((1 << UInt32(bitShift)) - 1)
            }
        }
        return BigUInt(words: out).normalized()
    }

    static func <<= (a: inout BigUInt, shift: Int) { a = a << shift }
    static func >>= (a: inout BigUInt, shift: Int) { a = a >> shift }

    static func << (a: BigUInt, shift: Int) -> BigUInt {
        if shift == 0 { return a }
        if a.words.isEmpty { return a }
        let wordShift = shift / 32
        let bitShift = shift % 32
        var out = [UInt32](repeating: 0, count: a.words.count + wordShift + (bitShift > 0 ? 1 : 0))
        var carry: UInt64 = 0
        for i in 0..<a.words.count {
            let v = (UInt64(a.words[i]) << UInt64(bitShift)) | carry
            out[i + wordShift] = UInt32(truncatingIfNeeded: v)
            carry = v >> 32
        }
        if bitShift > 0 {
            out[a.words.count + wordShift] = UInt32(truncatingIfNeeded: carry)
        }
        return BigUInt(words: out).normalized()
    }

    static func % (a: BigUInt, m: BigUInt) -> BigUInt {
        if m.words.isEmpty { return BigUInt(0) }
        if a < m { return a }
        let (q, r) = a.divMod(m)
        _ = q
        return r
    }

    static func / (a: BigUInt, b: BigUInt) -> BigUInt { a.divMod(b).0 }

    static func * (a: BigUInt, b: UInt32) -> BigUInt { a * BigUInt(UInt64(b)) }
    static func + (a: BigUInt, b: UInt32) -> BigUInt { a + BigUInt(UInt64(b)) }

    static func >> (a: BigUInt, shift: Int) -> BigUInt { a >> shift }

    func power(_ e: BigUInt, mod: BigUInt) -> BigUInt {
        var base = self % mod
        var exp = e
        var result = BigUInt(1)
        while exp > 0 {
            if exp.isOdd { result = (result * base) % mod }
            exp >>= 1
            base = (base * base) % mod
        }
        return result
    }

    func power(_ e: Int, mod: BigUInt) -> BigUInt {
        power(BigUInt(UInt64(e)), mod: mod)
    }

    private func divMod(_ v: BigUInt) -> (BigUInt, BigUInt) {
        precondition(!v.words.isEmpty)
        if self < v { return (BigUInt(0), self) }
        if v.words.count == 1 {
            return divModSmall(v.words[0])
        }
        var remainder = BigUInt(0)
        var quotient = BigUInt(0)
        let totalBits = self.bitWidth
        for i in stride(from: totalBits - 1, through: 0, by: -1) {
            remainder <<= 1
            if self.bit(at: i) { remainder = remainder + 1 }
            if remainder >= v {
                remainder = remainder - v
                quotient.setBit(i)
            }
        }
        return (quotient.normalized(), remainder.normalized())
    }

    private func divModSmall(_ d: UInt32) -> (BigUInt, BigUInt) {
        var out = [UInt32](repeating: 0, count: words.count)
        var rem: UInt64 = 0
        for i in stride(from: words.count - 1, through: 0, by: -1) {
            let cur = (rem << 32) | UInt64(words[i])
            let q = cur / UInt64(d)
            rem = cur % UInt64(d)
            out[i] = UInt32(q)
        }
        return (BigUInt(words: out).normalized(), BigUInt(UInt64(rem)))
    }

    var bitWidth: Int {
        if words.isEmpty { return 0 }
        let last = words.last!
        return (words.count - 1) * 32 + (32 - last.leadingZeroBitCount)
    }

    private func bit(at index: Int) -> Bool {
        let w = index / 32
        let b = index % 32
        if w >= words.count { return false }
        return ((words[w] >> UInt32(b)) & 1) == 1
    }

    private mutating func setBit(_ index: Int) {
        let w = index / 32
        let b = index % 32
        if w >= words.count { words += [UInt32](repeating: 0, count: w - words.count + 1) }
        words[w] |= (1 << UInt32(b))
    }

    func toMinimalBytes() -> Data {
        if words.isEmpty { return Data() }
        var data = Data()
        for w in words.reversed() {
            data.append(UInt8((w >> 24) & 0xFF))
            data.append(UInt8((w >> 16) & 0xFF))
            data.append(UInt8((w >> 8) & 0xFF))
            data.append(UInt8(w & 0xFF))
        }
        while data.first == 0 { data.removeFirst() }
        return data
    }

    func toFixed32() -> Data {
        var d = toMinimalBytes()
        if d.count > 32 { d = d.suffix(32) }
        if d.count < 32 { d = Data(repeating: 0, count: 32 - d.count) + d }
        return d
    }

    init(words: [UInt32]) { self.words = words }
    private func normalized() -> BigUInt {
        var w = words
        while let last = w.last, last == 0 { w.removeLast() }
        return BigUInt(words: w)
    }
}

extension BigUInt {
    static func * (a: BigUInt, b: BigUInt) -> BigUInt { a * b }
    static func + (a: BigUInt, b: BigUInt) -> BigUInt { a + b }
}

extension BigUInt {
    static func - (lhs: BigUInt, rhs: BigUInt) -> BigUInt { lhs - rhs }
}

extension BigUInt {
    static func * (lhs: BigUInt, rhs: UInt64) -> BigUInt { lhs * BigUInt(rhs) }
    static func + (lhs: BigUInt, rhs: UInt64) -> BigUInt { lhs + BigUInt(rhs) }
}

extension BigUInt {
    static func >> (lhs: BigUInt, rhs: UInt64) -> BigUInt { lhs >> Int(rhs) }
    static func << (lhs: BigUInt, rhs: UInt64) -> BigUInt { lhs << Int(rhs) }
}

extension BigUInt {
    func rlpItem() -> RLPItem { .bytes(self.toMinimalBytes().rlpScalarBytes()) }
}

private extension Data {
    func rlpItem() -> RLPItem { .bytes(self.rlpScalarBytes()) }
    func rlpScalarBytes() -> Data {
        if self.count == 1, self.first == 0 { return Data() }
        return self
    }
}

// MARK: - Utilities

private extension String {
    func strip0x() -> String {
        if lowercased().hasPrefix("0x") { return String(dropFirst(2)) }
        return self
    }
}

private extension Data {
    init?(hex: String) {
        let s = hex.strip0x()
        if s.isEmpty { self = Data(); return }
        if s.count % 2 != 0 { return nil }
        var out = Data()
        out.reserveCapacity(s.count / 2)
        var idx = s.startIndex
        while idx < s.endIndex {
            let next = s.index(idx, offsetBy: 2)
            let byteStr = s[idx..<next]
            guard let b = UInt8(byteStr, radix: 16) else { return nil }
            out.append(b)
            idx = next
        }
        self = out
    }

    func hexString() -> String {
        map { String(format: "%02x", $0) }.joined()
    }
}